const crypto = require('crypto');
function verify(item, secret, tol = 300) {
  const h = item.headers ?? {};
  const ts = parseInt(h['x-managecall-timestamp'] ?? '0', 10);
  if (Math.abs(Date.now() / 1000 - ts) > tol) throw new Error('timestamp_expired');
  const body = typeof item.body === 'string' ? item.body : JSON.stringify(item.body ?? {});
  const expected = 'sha256=' + crypto.createHmac('sha256', secret).update(`${ts}.${body}`).digest('hex');
  if (!crypto.timingSafeEqual(Buffer.from(expected), Buffer.from(h['x-managecall-signature-256'] ?? ''))) throw new Error('invalid_signature');
}
verify($input.first(), $env.MANAGECALL_WEBHOOK_SECRET);
return $input.all();

// Configure blocked phrases via COMPLIANCE_KEYWORDS env var (comma-separated).
// Example: COMPLIANCE_KEYWORDS="guaranteed return,no risk,off the books"
const keywordEnv = $env.COMPLIANCE_KEYWORDS ?? '';
const keywords = keywordEnv.split(',').map(k => k.trim().toLowerCase()).filter(Boolean);

const analysis = $input.first().json.data ?? {};
const transcript = (analysis.transcript_text ?? '').toLowerCase();

const matched = keywords.filter(kw => transcript.includes(kw));
const triggered = matched.length > 0;

return [{
  json: {
    triggered,
    matched_keywords: matched,
    analysis_id: analysis.id,
    recording_id: analysis.recording_id,
    transcript_excerpt: transcript.slice(0, 500),
    tenant_id: $('Webhook Trigger').item.json.body?.tenant_id,
  }
}];
